-- Post-import: mark departure_only records
UPDATE usage_records SET data_quality = 'departure_only' WHERE is_historical = 1 AND record_type = 'departure' AND data_quality = 'normal' AND id NOT IN (SELECT ur1.id FROM usage_records ur1 INNER JOIN usage_records ur2 ON ur1.car_id = ur2.car_id AND ur2.record_type = 'return' AND ur2.datetime > ur1.datetime AND ur2.datetime <= datetime(ur1.datetime, '+24 hours') WHERE ur1.is_historical = 1 AND ur1.record_type = 'departure' AND ur1.data_quality = 'normal');
